mapper.select:
SELECT r.id,r.title,r.cover,r.resource_type,r.resource_id,r.recommend_type,r.status,r.sort_order,r.create_time,r.update_time, CASE WHEN r.resource_type = 'singer' THEN (SELECT name FROM singer WHERE id = r.resource_id) WHEN r.resource_type = 'song' THEN (SELECT name FROM song WHERE id = r.resource_id) WHEN r.resource_type = 'playlist' THEN (SELECT name FROM playlist WHERE id = r.resource_id) END AS resource_name, CASE WHEN r.resource_type = 'singer' THEN (SELECT avatar FROM singer WHERE id = r.resource_id) WHEN r.resource_type = 'song' THEN (SELECT cover FROM song WHERE id = r.resource_id) WHEN r.resource_type = 'playlist' THEN (SELECT cover FROM playlist WHERE id = r.resource_id) END AS resource_cover, CASE WHEN r.resource_type = 'singer' THEN (SELECT url FROM song WHERE singer_id = r.resource_id AND status = 1 ORDER BY play_count DESC, sort_order ASC, create_time DESC LIMIT 1) WHEN r.resource_type = 'song' THEN (SELECT url FROM song WHERE id = r.resource_id) WHEN r.resource_type = 'playlist' THEN ( SELECT s.url FROM playlist_song ps INNER JOIN song s ON s.id = ps.song_id WHERE ps.playlist_id = r.resource_id AND s.status = 1 ORDER BY ps.sort_order ASC, s.play_count DESC, s.create_time DESC LIMIT 1 ) END AS resource_url, CASE WHEN r.resource_type = 'singer' THEN COALESCE((SELECT SUM(play_count) FROM song WHERE singer_id = r.resource_id AND status = 1), 0) WHEN r.resource_type = 'song' THEN COALESCE((SELECT play_count FROM song WHERE id = r.resource_id), 0) WHEN r.resource_type = 'playlist' THEN COALESCE(( SELECT SUM(s.play_count) FROM playlist_song ps INNER JOIN song s ON s.id = ps.song_id WHERE ps.playlist_id = r.resource_id AND s.status = 1 ), 0) END AS play_count, CASE WHEN r.resource_type = 'singer' THEN COALESCE((SELECT SUM(like_count) FROM song WHERE singer_id = r.resource_id AND status = 1), 0) WHEN r.resource_type = 'song' THEN COALESCE((SELECT like_count FROM song WHERE id = r.resource_id), 0) WHEN r.resource_type = 'playlist' THEN COALESCE(( SELECT SUM(s.like_count) FROM playlist_song ps INNER JOIN song s ON s.id = ps.song_id WHERE ps.playlist_id = r.resource_id AND s.status = 1 ), 0) END AS like_count, CASE WHEN r.resource_type = 'singer' THEN COALESCE((SELECT SUM(fav_count) FROM song WHERE singer_id = r.resource_id AND status = 1), 0) WHEN r.resource_type = 'song' THEN COALESCE((SELECT fav_count FROM song WHERE id = r.resource_id), 0) WHEN r.resource_type = 'playlist' THEN COALESCE(( SELECT SUM(s.fav_count) FROM playlist_song ps INNER JOIN song s ON s.id = ps.song_id WHERE ps.playlist_id = r.resource_id AND s.status = 1 ), 0) END AS fav_count FROM recommend r
AND r.recommend_type = #{recommendType} AND r.resource_type = #{resourceType} AND r.status = #{status}
ORDER BY like_count DESC, r.sort_order ASC, r.create_time DESC ORDER BY fav_count DESC, r.sort_order ASC, r.create_time DESC ORDER BY play_count DESC, r.sort_order ASC, r.create_time DESC ORDER BY r.sort_order ASC, r.create_time DESC
